// // This module decrements the 4-bit binary counter on each positive edge of the clock signal, and resets it to 15 when reset is asserted.
module top_module(
    input clk,
    input reset,
    output reg [3:0] count
);always @(posedge clk) begin
    if (reset == 0) begin
        count <= 4'b0000;
    end else begin
        count <= count + 1;
    end
end

endmodule
